mapper.sql:
/* wms-outbound-obmoveob-sql-oracle.xml - selectMoveObLblSql - 이고 출고 - 출고 라벨 정보 조회 */ SELECT 0 AS CHK /*체크 박스*/ , OBHD.CTKEY /*센터 코드*/ , OBHD.OWKEY /*화주 코드*/ , OBHD.OBHDDAY /*출고 헤더 일자*/ , OBHD.TOCTKEY /*TO 센터 코드*/ , OBHD.ORHDKEY /*SO 주문 번호*/ , OBHD.OBORDKEY /*오더 코드*/ , OBHD.OBHDKEY /*릴리즈코드*/ , OBHD.OBHDTYPECD /*출고 헤더 유형 코드*/ , OBHD.OBSTATUSCD /*출고 상태 코드*/ , MC.MVOBGRPNO /*이고 그룹 번호*/ , MC.CNFRMYN /*확정여부*/ , MC.CNTRBARCODE /*용기 바코드*/ , MC.CNTRWKURKEY /*용기 작업자*/ , MC.UPDATEDATE /*수정일시*/ , CNTR.CNTRDIVCD /*용기구분코드*/ , CT.CTNM /*센터명*/ , TOCT.CTNM AS TOCTNM /*TO센터명*/ , COUNT(DISTINCT MCDT.ICKEY) AS SKU /*상품 최소 분류 단위*/ , SUM(MCDT.QTY) AS EA /*총수량*/ , SUM(MCDT.QTY * IC.SLPRC) AS AMT /*총금액*/ FROM TWORK_INFO_OB_HD OBHD /*출고 공통 정보*/ INNER JOIN TWORK_INFO_MVOB_CNTR MC /*이고 용기 정보*/ ON OBHD.CTKEY = MC.CTKEY AND OBHD.OWKEY = MC.OWKEY AND OBHD.OBHDKEY = MC.OBHDKEY INNER JOIN TWORK_INFO_MVOB_CNTR_DT MCDT /*이고 용기 상세 정보*/ ON MC.CTKEY = MCDT.CTKEY AND MC.OWKEY = MCDT.OWKEY AND MC.OBHDKEY = MCDT.OBHDKEY AND MC.CNTRBARCODE = MCDT.CNTRBARCODE INNER JOIN TWORK_MST_IC IC /*상품 마스터*/ ON MCDT.CTKEY = IC.CTKEY AND MCDT.OWKEY = IC.OWKEY AND MCDT.ICKEY = IC.ICKEY LEFT JOIN TWORK_MST_CNTR CNTR /*용기마스터*/ ON MCDT.CTKEY = CNTR.CTKEY AND MCDT.CNTRBARCODE = CNTR.CNTRBARCODE INNER JOIN TWORK_MST_CT CT /*센터 마스터*/ ON OBHD.CTKEY = CT.CTKEY INNER JOIN TWORK_MST_CT TOCT /*센터 마스터 TOCTKEY*/ ON OBHD.TOCTKEY = TOCT.CTKEY
#{SEARCH_CONDITION}
#{cond}
AND OBHD.OBHDTYPECD = #{obhdtypecd} AND OBHD.CNTRWKCOMPLYN = 'Y' AND MC.CNTRDDLNYN = 'Y'
GROUP BY OBHD.CTKEY /*센터 코드*/ , OBHD.OWKEY /*화주 코드*/ , OBHD.OBHDDAY /*출고 헤더 일자*/ , OBHD.TOCTKEY /*TO 센터 코드*/ , OBHD.ORHDKEY /*SO 주문 번호*/ , OBHD.OBORDKEY /*오더 코드*/ , OBHD.OBHDKEY /*릴리즈코드*/ , OBHD.OBHDTYPECD /*출고 헤더 유형 코드*/ , OBHD.OBSTATUSCD /*출고 상태 코드*/ , MC.MVOBGRPNO /*이고 그룹 번호*/ , MC.CNFRMYN /*확정여부*/ , MC.CNTRBARCODE /*용기 바코드*/ , MC.CNTRWKURKEY /*용기 작업자*/ , MC.UPDATEDATE /*수정일시*/ , CNTR.CNTRDIVCD /*용기구분코드*/ , CT.CTNM /*센터명*/ , TOCT.CTNM /*TO센터명*/

