mapper.sql:
/* wms-outbound-obmoveob-sql-oracle.xml - selectMoveObLblDtSql - 이고 출고 - 출고 라벨 상세정보 조회 */ SELECT MCDT.CTKEY /*센터 코드*/ , MCDT.OWKEY /*화주 코드*/ , OBDT.OBORDKEY /*오더코드*/ , MCDT.CNTRBARCODE /*용기 바코드*/ , OBDT.OBORDDTKEY /*오더 상세 코드*/ , ASRT.ASRTMASICKEY /*아소트 모상품 코드*/ , ASRTIC.ICNM AS ASRTMASICNM /*아소트 모상품 명*/ , IC.ASRTYN /*아소트여부*/ , MCDT.ICKEY /*상품코드*/ , IC.ICNM /*상품명*/ , MCDT.IVATKEY /*재고 속성 코드*/ , MCDT.UOM /*단위*/ , MCDT.QTY /*수량*/ , COALESCE(ROUND((MCDT.QTY / INN.ICUNITQTY), 2), 0) AS INNQTY /*중포수량*/ , COALESCE(ROUND((MCDT.QTY / CTN.ICUNITQTY), 2), 0) AS CTNQTY /*카톤수량*/ , COALESCE(ROUND((MCDT.QTY / PLT.ICUNITQTY), 2), 0) AS PLTQTY /*파레트수량*/ , COALESCE((MCDT.QTY * IC.SLPRC), 0) AS AMT /*금액*/ , MCDT.INSERTDATE /*입력일시*/ , MCDT.INSERTURKEY /*입력자*/ , MCDT.UPDATEDATE /*수정일시*/ , MCDT.UPDATEURKEY /*수정자*/ FROM TWORK_INFO_OB_HD OBHD /*출고 공통 정보*/ INNER JOIN TWORK_INFO_MVOB_CNTR MC /*이고 용기 정보*/ ON OBHD.CTKEY = MC.CTKEY AND OBHD.OWKEY = MC.OWKEY AND OBHD.OBHDKEY = MC.OBHDKEY INNER JOIN TWORK_INFO_MVOB_CNTR_DT MCDT /*이고 용기 상세정보*/ ON MC.CTKEY = MCDT.CTKEY AND MC.OWKEY = MCDT.OWKEY AND MC.OBHDKEY = MCDT.OBHDKEY AND MC.CNTRBARCODE = MCDT.CNTRBARCODE INNER JOIN TWORK_INFO_OB_DT OBDT /*출고 상세 정보*/ ON MCDT.CTKEY = OBDT.CTKEY AND MCDT.OWKEY = OBDT.OWKEY AND MCDT.OBHDKEY = OBDT.OBHDKEY AND MCDT.OBDTKEY = OBDT.OBDTKEY INNER JOIN TWORK_MST_IC IC /*상품 마스터*/ ON OBDT.CTKEY = IC.CTKEY AND OBDT.OWKEY = IC.OWKEY AND OBDT.ICKEY = IC.ICKEY LEFT OUTER JOIN TWORK_MST_ASRT ASRT /*아소트정보*/ ON IC.CTKEY = ASRT.CTKEY AND IC.OWKEY = ASRT.OWKEY AND IC.ICKEY = ASRT.ASRTDTICKEY AND IC.ASRTYN = 'Y' LEFT OUTER JOIN TWORK_MST_IC ASRTIC /*상품마스터(아소트)*/ ON ASRT.CTKEY = ASRTIC.CTKEY AND ASRT.OWKEY = ASRTIC.OWKEY AND ASRT.ASRTMASICKEY = ASRTIC.ICKEY LEFT OUTER JOIN TWORK_MST_ICUTXTYPE INN /*상품단위유형마스터*/ ON IC.CTKEY = INN.CTKEY AND IC.OWKEY = INN.OWKEY AND IC.ICKEY = INN.ICKEY AND INN.ICUNITTYPECD = 'INN' /*INN: 중포*/ LEFT OUTER JOIN TWORK_MST_ICUTXTYPE CTN ON IC.CTKEY = CTN.CTKEY AND IC.OWKEY = CTN.OWKEY AND IC.ICKEY = CTN.ICKEY AND CTN.ICUNITTYPECD = 'CTN' /*CTN: 카톤*/ LEFT OUTER JOIN TWORK_MST_ICUTXTYPE PLT ON IC.CTKEY = PLT.CTKEY AND IC.OWKEY = PLT.OWKEY AND IC.ICKEY = PLT.ICKEY AND PLT.ICUNITTYPECD = 'PLT' /*PLT: 파레트*/ WHERE OBHD.CTKEY = #{ctkey} AND OBHD.OWKEY = #{owkey} AND OBHD.OBHDTYPECD = #{obhdtypecd} AND OBHD.OBORDKEY = #{obordkey}
#{cond}
AND MC.CNTRDDLNYN = 'Y' AND MC.CNTRBARCODE = #{cntrbarcode} AND OBHD.CNTRWKCOMPLYN = 'Y' ORDER BY OBDT.OBORDDTKEY

