mapper.update:
/* wms-outbound-obmoveob-sql-oracle.xml - updateMvobGrpNo - 이고 출고 - 이고 그룹번호 업데이트 */
UPDATE TWORK_INFO_MVOB_CNTR /*출고 공통 정보*/
   SET MVOBGRPNO = #{mvobgrpno}
     , UPDATEDATE = #{sysdate}
     , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBHDKEY = #{obhdkey}

   AND CNTRBARCODE = #{cntrbarcode}

mapper.sql:
/* wms-outbound-obmoveob-sql-oracle.xml - selectMoveObSql - 이고 출고 - 출고 정보 조회 */ SELECT 0 AS CHK /*체크박스*/ , OBHD.CTKEY /*센터 코드*/ , OBHD.OWKEY /*화주 코드*/ , OBHD.OBHDDAY /*출고 헤더 일자*/ , OBHD.TOCTKEY /*TO 센터 코드*/ , OBHD.ORHDKEY /*주문 공통 코드*/ , OBHD.OBORDKEY /*오더 코드*/ , OBHD.OBHDKEY /*릴리즈 코드*/ , OBHD.OBHDTYPECD /*출고 헤더 유형 코드*/ , OBHD.OBSTATUSCD /*출고 상태 코드*/ , MC.MVOBGRPNO /*이고 그룹 번호*/ , CT.CTNM /*센터명*/ , TOCT.CTNM AS TOCTNM /*TO센터명*/ , CASE WHEN COUNT(*) = SUM(CASE WHEN MC.CNFRMYN = 'Y' THEN 1 ELSE 0 END) THEN 'Y' ELSE 'N' END AS CNFRMYN /*확정여부*/ FROM TWORK_INFO_OB_HD OBHD /*출고 공통 정보*/ INNER JOIN TWORK_INFO_MVOB_CNTR MC /*이고 용기 정보*/ ON OBHD.CTKEY = MC.CTKEY AND OBHD.OWKEY = MC.OWKEY AND OBHD.OBHDKEY = MC.OBHDKEY INNER JOIN TWORK_MST_CT CT /*센터 마스터*/ ON OBHD.CTKEY = CT.CTKEY INNER JOIN TWORK_MST_CT TOCT /*센터 마스터 TOCTKEY*/ ON OBHD.TOCTKEY = TOCT.CTKEY
#{SEARCH_CONDITION}
#{cond}
AND OBHD.OBHDTYPECD = #{obhdtypecd} AND OBHD.CNTRWKCOMPLYN = 'Y' AND MC.MVOBGRPNO IS NOT NULL AND MC.CNTRDDLNYN = 'Y' /*용기마감여부*/
GROUP BY OBHD.CTKEY , OBHD.OWKEY , OBHD.OBHDDAY , OBHD.TOCTKEY , OBHD.ORHDKEY , OBHD.OBORDKEY , OBHD.OBHDKEY , OBHD.OBHDTYPECD , OBHD.OBSTATUSCD , MC.MVOBGRPNO , CT.CTNM , TOCT.CTNM

